solution: ```class Solution {
    public int hardestWorker(int n, int[][] logs) {
        int maxTime = logs[0][1];
        int bestId = logs[0][0];
        for (int i = 1; i < logs.length; ++i) {
            int duration = logs[i][1] - logs[i - 1][1];
            if (duration > maxTime) {
                maxTime = duration;
                bestId = logs[i][0];
            } else if (duration == maxTime && logs[i][0] < bestId) {
                bestId = logs[i][0];
            }
        }
        return bestId;
    }
}```
